function ppParseFormacion(str){if(!str)return null;var nums=str.split('-').map(Number);if(nums.length<3)return null;var all=[];for(var i=0;i<nums.length;i++){var yP=i===0?88:88-(i*(73/(nums.length-1)));for(var j=0;j<nums[i];j++){var xP;var c=nums[i];if(c===1)xP=50;else if(c===2)xP=35+j*30;else if(c===3)xP=22+j*28;else if(c===4)xP=14+j*24;else xP=10+j*(80/(c-1));all.push({slotId:i+'_'+j,x:xP,y:yP,lineIdx:i,posIdx:j})}}return all}
function ppRenderCampo(slots,lineup,jugadores,size){var dot=size==='big'?44:32;var fs=size==='big'?18:13;var ns=size==='big'?12:9;var bw=size==='big'?3:2;var click=size!=='big';var h='<div style="position:relative;width:100%;max-width:'+(size==='big'?600:500)+'px;margin:0 auto;aspect-ratio:68/105;background:linear-gradient(to bottom,#1a6b37,#1d7a3e,#1a6b37);border:'+bw+'px solid rgba(255,255,255,0.3);border-radius:8px;overflow:hidden">';h+='<div style="position:absolute;top:50%;left:0;right:0;height:1px;background:rgba(255,255,255,0.25)"></div><div style="position:absolute;top:50%;left:50%;width:80px;height:80px;border:1px solid rgba(255,255,255,0.25);border-radius:50%;transform:translate(-50%,-50%)"></div><div style="position:absolute;top:0;left:50%;width:120px;height:40px;border:1px solid rgba(255,255,255,0.2);border-bottom:1px solid rgba(255,255,255,0.25);transform:translateX(-50%);border-top:none"></div><div style="position:absolute;bottom:0;left:50%;width:120px;height:40px;border:1px solid rgba(255,255,255,0.2);border-top:1px solid rgba(255,255,255,0.25);transform:translateX(-50%);border-bottom:none"></div>';slots.forEach(function(s){var pi=lineup[s.slotId];var p=(pi!==undefined&&pi!==null&&jugadores[pi])?jugadores[pi]:null;var gk=s.lineIdx===0;var bg=p?(gk?'#f59e0b':'#3b82f6'):'rgba(255,255,255,0.15)';var bc=p?(gk?'#fbbf24':'#60a5fa'):'rgba(255,255,255,0.3)';var num=p?(p.number||'?'):'+';var nom=p?p.name.split(' ').pop().substring(0,10):'';var oc=click?' onclick="ppAbrirSelectorSlot(\''+s.slotId+'\')"':'';h+='<div'+oc+' style="position:absolute;left:'+s.x+'%;top:'+s.y+'%;transform:translate(-50%,-50%);'+(click?'cursor:pointer;':'')+'text-align:center;z-index:2"><div style="width:'+dot+'px;height:'+dot+'px;background:'+bg+';border:'+bw+'px solid '+bc+';border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:'+fs+'px;font-weight:700;color:#fff;margin:0 auto;box-shadow:0 2px 6px rgba(0,0,0,0.4)">'+num+'</div>'+(nom?'<div style="font-size:'+ns+'px;color:#fff;text-shadow:0 1px 3px rgba(0,0,0,0.8);margin-top:2px;font-weight:600;white-space:nowrap">'+ppEsc(nom)+'</div>':'')+'</div>'});return h+'</div>'}
function ppRenderAlineacion(){var p=pp.planActual;if(!p||!p.rival_formation)return '<div style="padding:16px;background:#1e293b;border-radius:8px;text-align:center;color:#475569;font-size:12px;margin-top:12px">Selecciona formacion para ver alineacion</div>';var s=ppParseFormacion(p.rival_formation);if(!s)return '';var lu=(p.weekly_map&&p.weekly_map.rival_lineup)||{};return '<div style="margin-top:16px"><h4 style="margin:0 0 10px;color:#e2e8f0;font-size:14px">⚽ Alineacion rival — '+p.rival_formation+'</h4>'+ppRenderCampo(s,lu,p.rival_players||[],'normal')+'</div>'}
function ppAbrirSelectorSlot(slotId){var jug=pp.planActual.rival_players||[];if(jug.length===0){showToast('Añade jugadores primero');return}var lu=(pp.planActual.weekly_map&&pp.planActual.weekly_map.rival_lineup)||{};var asig={};Object.keys(lu).forEach(function(k){if(lu[k]!==null&&lu[k]!==undefined)asig[lu[k]]=true});var prev=document.getElementById('pp-slot-overlay');if(prev)prev.remove();var ov=document.createElement('div');ov.id='pp-slot-overlay';ov.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';ov.onclick=function(e){if(e.target===ov)ov.remove()};var h='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;max-width:360px;width:100%;padding:20px;max-height:70vh;overflow-y:auto"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px"><h4 style="margin:0;color:#e2e8f0;font-size:14px">Asignar jugador</h4><button onclick="document.getElementById(\'pp-slot-overlay\').remove()" style="background:none;border:none;color:#9ca3af;font-size:18px;cursor:pointer">✕</button></div><div onclick="ppAsignarSlot(\''+slotId+'\',null)" style="padding:10px;background:#1e293b;border:1px solid #334155;border-radius:8px;cursor:pointer;margin-bottom:6px;font-size:12px;color:#64748b;text-align:center">— Sin asignar —</div>';jug.forEach(function(j,idx){var ya=asig[idx]&&lu[slotId]!==idx;h+='<div onclick="'+(ya?'':'ppAsignarSlot(\''+slotId+'\','+idx+')')+'" style="display:flex;align-items:center;gap:10px;padding:10px;background:#1e293b;border:1px solid #334155;border-radius:8px;margin-bottom:4px;cursor:'+(ya?'not-allowed':'pointer')+';opacity:'+(ya?'0.4':'1')+'"><div style="width:28px;height:28px;background:#0f172a;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;color:#f59e0b">'+(j.number||'?')+'</div><div><div style="font-size:13px;color:#e2e8f0;font-weight:600">'+ppEsc(j.name)+'</div><div style="font-size:10px;color:#94a3b8">'+ppEsc(j.position||'')+'</div></div>'+(ya?'<div style="font-size:9px;color:#475569;margin-left:auto">asignado</div>':'')+'</div>'});ov.innerHTML=h+'</div>';document.body.appendChild(ov)}
async function ppAsignarSlot(slotId,pi){var wm=pp.planActual.weekly_map||{};if(!wm.rival_lineup)wm.rival_lineup={};wm.rival_lineup[slotId]=pi;try{var{error}=await supabaseClient.from('match_plans').update({weekly_map:wm,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.weekly_map=wm;var ov=document.getElementById('pp-slot-overlay');if(ov)ov.remove();ppMostrarTab('scouting')}catch(e){showToast('Error: '+e.message)}}

