function ppAbrirModalMedia(overlayId, onUrlSave, onFileSave) {
    var prev = document.getElementById(overlayId); if (prev) prev.remove();
    var ov = document.createElement('div'); ov.id = overlayId;
    ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
    ov.onclick = function(e) { if (e.target === ov) ov.remove(); };
    ov.innerHTML = '<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;max-width:480px;width:100%;padding:24px">' +
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px"><h3 style="margin:0;color:#e2e8f0;font-size:16px">Añadir video o imagen</h3><button onclick="document.getElementById(\'' + overlayId + '\').remove()" style="background:none;border:none;color:#9ca3af;font-size:20px;cursor:pointer">✕</button></div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px"><button onclick="ppModalMediaModo(\'' + overlayId + '\',\'url\')" id="' + overlayId + '-btn-url" style="padding:16px;background:#1e3a5f;border:2px solid #3b82f6;color:#93c5fd;border-radius:10px;cursor:pointer;font-size:13px;font-weight:600">🔗 Pegar URL<br><span style="font-size:11px;font-weight:400;color:#64748b">YouTube, Veo, TactiClip...</span></button><button onclick="ppModalMediaModo(\'' + overlayId + '\',\'file\')" id="' + overlayId + '-btn-file" style="padding:16px;background:#1e293b;border:2px solid #334155;color:#9ca3af;border-radius:10px;cursor:pointer;font-size:13px;font-weight:600">📁 Subir archivo<br><span style="font-size:11px;font-weight:400;color:#64748b">MP4, MOV, JPG, PNG...</span></button></div>' +
        '<div id="' + overlayId + '-url-area"><div style="margin-bottom:10px"><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">URL</label><input type="text" id="' + overlayId + '-url" placeholder="https://..." style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div style="margin-bottom:12px"><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">Titulo (opcional)</label><input type="text" id="' + overlayId + '-title" style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><button id="' + overlayId + '-url-btn" style="width:100%;padding:10px;background:#3b82f6;border:none;color:#fff;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600">Añadir</button></div>' +
        '<div id="' + overlayId + '-file-area" style="display:none"><div style="margin-bottom:10px"><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">Titulo (opcional)</label><input type="text" id="' + overlayId + '-file-title" style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div style="margin-bottom:12px"><input type="file" id="' + overlayId + '-file-input" accept="video/*,image/*" style="width:100%;padding:8px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div id="' + overlayId + '-progress" style="display:none;margin-bottom:12px"><div style="background:#1e293b;border-radius:4px;overflow:hidden;height:6px"><div id="' + overlayId + '-pbar" style="height:100%;background:#3b82f6;width:0%;transition:width 0.3s"></div></div><div id="' + overlayId + '-ptext" style="font-size:11px;color:#64748b;margin-top:4px;text-align:center"></div></div><button id="' + overlayId + '-upload-btn" style="width:100%;padding:10px;background:#f97316;border:none;color:#fff;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600">Subir archivo</button></div></div>';
    document.body.appendChild(ov);
    document.getElementById(overlayId + '-url-btn').onclick = function() {
        var url = document.getElementById(overlayId + '-url').value.trim();
        if (!url) { showToast('URL obligatoria'); return; }
        var title = document.getElementById(overlayId + '-title').value.trim() || '';
        var tipo = 'link';
        if (url.match(/\.(mp4|mov|webm)$/i) || url.indexOf('youtube') >= 0 || url.indexOf('youtu.be') >= 0 || url.indexOf('veo.co') >= 0) tipo = 'video';
        else if (url.match(/\.(jpg|jpeg|png|gif|webp)$/i)) tipo = 'image';
        onUrlSave(url, title, tipo);
        document.getElementById(overlayId).remove();
    };
    document.getElementById(overlayId + '-upload-btn').onclick = function() {
        var fi = document.getElementById(overlayId + '-file-input');
        var file = fi.files[0]; if (!file) { showToast('Selecciona archivo'); return; }
        var title = document.getElementById(overlayId + '-file-title').value.trim() || file.name;
        var btn = document.getElementById(overlayId + '-upload-btn');
        var pa = document.getElementById(overlayId + '-progress');
        var pb = document.getElementById(overlayId + '-pbar');
        var pt = document.getElementById(overlayId + '-ptext');
        ppSubirArchivo(file, title, btn, pa, pb, pt, function(url, tipo) {
            onFileSave(url, title, tipo);
            document.getElementById(overlayId).remove();
        });
    };
}
function ppModalMediaModo(oid, m) {
    var u = document.getElementById(oid + '-url-area'), f = document.getElementById(oid + '-file-area');
    var bu = document.getElementById(oid + '-btn-url'), bf = document.getElementById(oid + '-btn-file');
    if (m === 'url') { u.style.display = 'block'; f.style.display = 'none'; bu.style.background = '#1e3a5f'; bu.style.borderColor = '#3b82f6'; bu.style.color = '#93c5fd'; bf.style.background = '#1e293b'; bf.style.borderColor = '#334155'; bf.style.color = '#9ca3af'; }
    else { u.style.display = 'none'; f.style.display = 'block'; bf.style.background = '#1e3a5f'; bf.style.borderColor = '#f97316'; bf.style.color = '#fdba74'; bu.style.background = '#1e293b'; bu.style.borderColor = '#334155'; bu.style.color = '#9ca3af'; }
}

