function initPlanPartido(){var r=document.getElementById('planpartido-root');if(!r)return;ppRenderMain();ppCargarPartidosPendientes()}
function ppRenderMain(){var r=document.getElementById('planpartido-root');if(!r)return;r.innerHTML='<div style="max-width:1200px;margin:0 auto;padding:10px 0"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;flex-wrap:wrap;gap:10px"><h2 style="margin:0;font-size:20px;color:#e2e8f0">📋 Plan de Partido</h2><div id="pp-status-badge"></div></div><div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:16px;margin-bottom:16px"><label style="font-size:13px;color:#9ca3af;display:block;margin-bottom:6px">Selecciona el proximo partido:</label><select id="pp-partido-select" onchange="ppSeleccionarPartido()" style="width:100%;padding:10px 14px;background:#1e293b;border:1px solid #334155;border-radius:8px;color:#e2e8f0;font-size:14px"><option value="">-- Elige un partido pendiente --</option></select></div><div id="pp-contenido" style="display:none"></div></div>'}
async function ppCargarPartidosPendientes(){if(!clubId||!seasonId)return;var s=document.getElementById('pp-partido-select');if(!s)return;try{var{data:p,error}=await supabaseClient.from('matches').select('*').eq('club_id',clubId).eq('season_id',seasonId).is('result',null).order('match_date',{ascending:true});if(error)throw error;if(!p||p.length===0){s.innerHTML='<option value="">-- Sin partidos --</option>';return}var h='<option value="">-- Elige partido --</option>';p.forEach(function(m){var f=new Date(m.match_date+'T12:00:00');var ds=['Dom','Lun','Mar','Mie','Jue','Vie','Sab'][f.getDay()];h+='<option value="'+m.id+'">'+ds+' '+f.getDate()+'/'+(f.getMonth()+1)+(m.kick_off_time?' '+m.kick_off_time.slice(0,5):'')+' — '+(m.home_away==='home'?'vs ':'@ ')+m.opponent+(m.competition?' · '+m.competition:'')+'</option>'});s.innerHTML=h}catch(e){showToast('Error: '+e.message)}}
async function ppSeleccionarPartido(){var s=document.getElementById('pp-partido-select'),mid=s.value,c=document.getElementById('pp-contenido');if(!mid){c.style.display='none';pp.planActual=null;pp.partidoActual=null;ppRenderStatusBadge();return}c.style.display='block';c.innerHTML='<div style="text-align:center;padding:40px;color:#64748b">Cargando...</div>';try{var{data:partido,error:e1}=await supabaseClient.from('matches').select('*').eq('id',mid).single();if(e1)throw e1;pp.partidoActual=partido;var{data:rival}=await supabaseClient.from('opponents').select('*').eq('club_id',clubId).eq('name',partido.opponent).single();pp.rivalActual=rival||null;var{data:plan,error:e2}=await supabaseClient.from('match_plans').select('*').eq('match_id',mid).single();if(e2&&e2.code==='PGRST116'){var{data:np,error:e3}=await supabaseClient.from('match_plans').insert({club_id:clubId,season_id:seasonId,match_id:mid,status:'draft'}).select().single();if(e3)throw e3;plan=np;showToast('Plan creado')}else if(e2)throw e2;pp.planActual=plan;ppRenderContenido()}catch(e){c.innerHTML='<div style="text-align:center;padding:40px;color:#ef4444">Error: '+e.message+'</div>'}}

// =============================================
// CABECERA + STATUS
// =============================================
function ppRenderCabecera(){var p=pp.partidoActual;if(!p)return '';var f=new Date(p.match_date+'T12:00:00');var fl=f.toLocaleDateString('es-ES',{weekday:'long',day:'numeric',month:'long',year:'numeric'});var eL=p.home_away==='home';var h=p.kick_off_time?p.kick_off_time.slice(0,5):'';var co=p.competition||'';var eR=(pp.rivalActual&&pp.rivalActual.logo_url)?'<img src="'+pp.rivalActual.logo_url+'" style="width:48px;height:48px;object-fit:contain;border-radius:8px">':'<div style="width:48px;height:48px;background:#1e293b;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:24px">🛡️</div>';var eP=(clubData&&clubData.logo_url)?'<img src="'+clubData.logo_url+'" style="width:48px;height:48px;object-fit:contain;border-radius:8px">':'<div style="width:48px;height:48px;background:#1e293b;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:24px">🏠</div>';var nL=eL?((clubData&&clubData.name)||'Mi Equipo'):p.opponent;var nV=eL?p.opponent:((clubData&&clubData.name)||'Mi Equipo');return '<div style="background:linear-gradient(135deg,#0f172a,#1e293b);border:1px solid #1e3a5f;border-radius:12px;padding:20px;margin-bottom:16px"><div style="display:flex;align-items:center;justify-content:center;gap:20px;flex-wrap:wrap"><div style="text-align:center">'+(eL?eP:eR)+'<div style="font-size:14px;font-weight:700;color:#e2e8f0;margin-top:6px">'+nL+'</div></div><div style="text-align:center;padding:0 10px"><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:1px">'+co+'</div><div style="font-size:24px;font-weight:700;color:#f59e0b;margin:4px 0">VS</div><div style="font-size:13px;color:#94a3b8">'+fl+'</div>'+(h?'<div style="font-size:13px;color:#94a3b8">'+h+'h</div>':'')+'</div><div style="text-align:center">'+(eL?eR:eP)+'<div style="font-size:14px;font-weight:700;color:#e2e8f0;margin-top:6px">'+nV+'</div></div></div></div>'}
function ppRenderStatusBadge(){var b=document.getElementById('pp-status-badge');if(!b)return;if(!pp.planActual){b.innerHTML='';return}var s=pp.planActual.status;var c={draft:{bg:'#1e293b',bc:'#475569',tc:'#94a3b8',l:'📝 Borrador'},ready:{bg:'#052e16',bc:'#15803d',tc:'#4ade80',l:'✅ Listo'},presented:{bg:'#172554',bc:'#1d4ed8',tc:'#60a5fa',l:'📊 Presentado'}}[s]||{bg:'#1e293b',bc:'#475569',tc:'#94a3b8',l:'📝 Borrador'};b.innerHTML='<div style="display:flex;align-items:center;gap:8px"><span style="padding:5px 14px;background:'+c.bg+';border:1px solid '+c.bc+';color:'+c.tc+';border-radius:20px;font-size:12px;font-weight:600">'+c.l+'</span><select onchange="ppCambiarEstado(this.value)" style="padding:5px 8px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#94a3b8;font-size:11px"><option value="draft"'+(s==='draft'?' selected':'')+'>Borrador</option><option value="ready"'+(s==='ready'?' selected':'')+'>Listo</option><option value="presented"'+(s==='presented'?' selected':'')+'>Presentado</option></select></div>'}
async function ppCambiarEstado(e){if(!pp.planActual)return;try{var{error}=await supabaseClient.from('match_plans').update({status:e,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.status=e;ppRenderStatusBadge();showToast('Estado: '+e)}catch(r){showToast('Error: '+r.message)}}

// =============================================
// CONTENIDO + TABS
// =============================================
function ppRenderContenido(){var c=document.getElementById('pp-contenido');if(!c)return;ppRenderStatusBadge();var h=ppRenderCabecera();h+='<div id="pp-tabs" style="display:flex;gap:4px;margin-bottom:16px;flex-wrap:wrap">'+ppTabBtn('scouting','🔍 Scouting',true)+ppTabBtn('jugadores','👤 Jugadores rival',false)+ppTabBtn('fases','⚽ Momentos juego',false)+ppTabBtn('tactica','⚔️ Plan tactico',false)+ppTabBtn('semana','📅 Semana',false)+ppTabBtn('contenido','🎯 Contenido',false)+'</div><div id="pp-tab-content"></div>';c.innerHTML=h;ppMostrarTab('scouting')}
function ppTabBtn(id,l,a){return '<button onclick="ppMostrarTab(\''+id+'\')" id="pp-tab-'+id+'" style="padding:8px 16px;border-radius:8px;border:1px solid '+(a?'#3b82f6':'#334155')+';background:'+(a?'#1e3a5f':'#0f172a')+';color:'+(a?'#93c5fd':'#9ca3af')+';font-size:13px;font-weight:600;cursor:pointer">'+l+'</button>'}
function ppMostrarTab(t){['scouting','jugadores','fases','tactica','semana','contenido'].forEach(function(x){var b=document.getElementById('pp-tab-'+x);if(b){var a=x===t;b.style.borderColor=a?'#3b82f6':'#334155';b.style.background=a?'#1e3a5f':'#0f172a';b.style.color=a?'#93c5fd':'#9ca3af'}});var area=document.getElementById('pp-tab-content');if(!area)return;switch(t){case 'scouting':area.innerHTML=ppRenderScouting();break;case 'jugadores':area.innerHTML=ppRenderJugadores();break;case 'fases':area.innerHTML=ppRenderFases();break;case 'tactica':area.innerHTML=ppRenderTactica();break;case 'semana':area.innerHTML='<div style="text-align:center;padding:30px;color:#64748b">Cargando...</div>';ppCargarSemana();break;case 'contenido':area.innerHTML=ppRenderContenidos();break}}

// =============================================
// TAB: SCOUTING
// =============================================
function ppRenderScouting(){var p=pp.planActual;return '<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:20px"><h3 style="margin:0 0 16px;color:#e2e8f0;font-size:16px">🔍 Scouting del rival</h3><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px"><div><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">Formacion esperada</label>'+ppSelectFormacion('pp-rf',p.rival_formation,"ppGuardarCampo('rival_formation',this.value);setTimeout(function(){ppMostrarTab('scouting')},200)")+'</div><div><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">Estilo de juego</label><input type="text" value="'+ppEsc(p.rival_style)+'" onchange="ppGuardarCampo(\'rival_style\',this.value)" placeholder="Ej: Juego directo..." style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:14px"></div></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px"><div><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">💪 Puntos fuertes rival</label><textarea onchange="ppGuardarCampo(\'rival_strengths\',this.value)" rows="4" placeholder="¿Que hacen bien?" style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px;resize:vertical">'+ppEsc(p.rival_strengths)+'</textarea></div><div><label style="font-size:12px;color:#9ca3af;display:block;margin-bottom:4px">📉 Puntos debiles rival</label><textarea onchange="ppGuardarCampo(\'rival_weaknesses\',this.value)" rows="4" placeholder="¿Donde hacerles daño?" style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px;resize:vertical">'+ppEsc(p.rival_weaknesses)+'</textarea></div></div>'+ppRenderAlineacion()+'</div>'}

// =============================================
// TAB: JUGADORES RIVAL (con media)
// =============================================
function ppRenderJugadorMedia(media){if(!media||media.length===0)return '<div style="font-size:10px;color:#475569">Sin videos</div>';var h='';media.forEach(function(m,i){var ic=m.type==='video'?'🎬':(m.type==='image'?'🖼️':'🔗');var esDataUrl=m.url&&m.url.indexOf('data:')===0;h+='<div style="display:flex;align-items:center;gap:6px;background:#0f172a;border:1px solid #334155;border-radius:6px;padding:4px 8px;font-size:11px;margin-bottom:3px"><span>'+ic+'</span><a href="'+(esDataUrl?'#':ppEsc(m.url))+'" '+(esDataUrl?'onclick="event.preventDefault();ppVerImagen('+i+')"':'target="_blank"')+' style="color:#60a5fa;text-decoration:none;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+ppEsc(m.title||'Archivo')+'</a><button onclick="ppQuitarMediaJugador('+i+')" style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:13px;padding:0 2px">✕</button></div>'});return h}
function ppVerImagen(i){var m=_ppJugadorMedia[i];if(!m||!m.url)return;var prev=document.getElementById('pp-img-viewer');if(prev)prev.remove();var ov=document.createElement('div');ov.id='pp-img-viewer';ov.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.85);z-index:10001;display:flex;align-items:center;justify-content:center;padding:20px;cursor:pointer';ov.onclick=function(){ov.remove()};ov.innerHTML='<img src="'+m.url+'" style="max-width:90%;max-height:90%;border-radius:8px;box-shadow:0 4px 20px rgba(0,0,0,0.5)"><div style="position:absolute;top:16px;right:20px;color:#fff;font-size:24px;cursor:pointer">✕</div>';document.body.appendChild(ov)}
function ppQuitarMediaJugador(i){_ppJugadorMedia.splice(i,1);var l=document.getElementById('ppj-media-list');if(l)l.innerHTML=ppRenderJugadorMedia(_ppJugadorMedia)}
function ppAgregarMediaJugador(){ppAbrirModalMedia('pp-jm-overlay',function(url,title,tipo){_ppJugadorMedia.push({url:url,title:title,type:tipo});var l=document.getElementById('ppj-media-list');if(l)l.innerHTML=ppRenderJugadorMedia(_ppJugadorMedia);showToast('Añadido')},function(url,title,tipo){_ppJugadorMedia.push({url:url,title:title,type:tipo});var l=document.getElementById('ppj-media-list');if(l)l.innerHTML=ppRenderJugadorMedia(_ppJugadorMedia);showToast('Añadido')})}

function ppRenderJugadores(){var jug=pp.planActual.rival_players||[];var h='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:20px"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px"><h3 style="margin:0;color:#e2e8f0;font-size:16px">👤 Jugadores del rival ('+jug.length+')</h3><button onclick="ppAbrirFormJugador(-1)" style="padding:8px 16px;background:#3b82f6;border:none;color:#fff;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600">+ Añadir jugador</button></div><div id="pp-jugador-form-area" style="display:none;margin-bottom:16px"></div>';['porteros','defensas','medios','delanteros'].forEach(function(lk){var li=PP_LINEAS[lk];var jl=[];jug.forEach(function(j,i){if(li.posiciones.indexOf(j.position)>=0)jl.push({j:j,i:i})});h+='<div style="margin-bottom:16px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:8px"><div style="width:4px;height:18px;background:'+li.color+';border-radius:2px"></div><span style="font-size:13px;font-weight:600;color:'+li.color+';text-transform:uppercase">'+li.label+'</span><span style="font-size:11px;color:#64748b">('+jl.length+')</span></div>';if(jl.length===0)h+='<div style="padding:12px;background:#1e293b;border-radius:8px;color:#475569;font-size:12px;text-align:center">Sin jugadores</div>';else{h+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:8px">';jl.forEach(function(it){h+=ppRenderJugadorCard(it.j,it.i)});h+='</div>'}h+='</div>'});var sp=[];jug.forEach(function(j,i){var en=false;Object.keys(PP_LINEAS).forEach(function(k){if(PP_LINEAS[k].posiciones.indexOf(j.position)>=0)en=true});if(!en)sp.push({j:j,i:i})});if(sp.length>0){h+='<div style="margin-bottom:16px"><div style="font-size:13px;font-weight:600;color:#9ca3af;margin-bottom:8px">Sin posicion</div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:8px">';sp.forEach(function(it){h+=ppRenderJugadorCard(it.j,it.i)});h+='</div></div>'}return h+'</div>'}
function ppRenderJugadorCard(j,idx){var st='';if(j.games||j.minutes||j.goals){var p=[];if(j.games)p.push('PJ:'+j.games);if(j.minutes)p.push(j.minutes+"'");if(j.goals)p.push(j.goals+' gol'+(j.goals>1?'es':''));st=p.join(' · ')}return '<div style="background:#1e293b;border:1px solid #334155;border-radius:10px;padding:12px;cursor:pointer" onclick="ppAbrirFormJugador('+idx+')" onmouseenter="this.style.borderColor=\'#3b82f6\'" onmouseleave="this.style.borderColor=\'#334155\'"><div style="display:flex;align-items:center;gap:10px;margin-bottom:6px"><div style="width:32px;height:32px;background:#0f172a;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#f59e0b">'+(j.number||'?')+'</div><div style="flex:1;min-width:0"><div style="font-size:14px;font-weight:600;color:#e2e8f0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+ppEsc(j.name||'Sin nombre')+(j.year?' <span style="color:#64748b;font-weight:400;font-size:11px">('+j.year+')</span>':'')+'</div><div style="font-size:11px;color:#94a3b8">'+ppEsc(j.position||'')+(j.foot?' · '+j.foot:'')+'</div></div></div>'+(st?'<div style="font-size:11px;color:#64748b;margin-bottom:4px">'+st+'</div>':'')+(j.club_from?'<div style="font-size:10px;color:#475569;margin-bottom:4px">Procede: '+ppEsc(j.club_from)+'</div>':'')+(j.analysis?'<div style="font-size:11px;color:#94a3b8;line-height:1.4;max-height:44px;overflow:hidden">'+ppEsc(j.analysis)+'</div>':'<div style="font-size:11px;color:#475569;font-style:italic">Sin analisis</div>')+(j.media&&j.media.length>0?'<div style="font-size:10px;color:#60a5fa;margin-top:4px">🎬 '+j.media.length+' archivo'+(j.media.length>1?'s':'')+'</div>':'')+'</div>'}
function ppAbrirFormJugador(idx){pp.jugadorEditIdx=idx;var area=document.getElementById('pp-jugador-form-area');if(!area)return;var jug=pp.planActual.rival_players||[];var j=idx>=0?jug[idx]:{name:'',number:'',position:'',foot:'Diestro',year:'',club_from:'',games:'',minutes:'',goals:'',analysis:'',media:[]};_ppJugadorMedia=(j.media||[]).slice();var esE=idx>=0;var po='<option value="">Seleccionar...</option>';PP_POSICIONES.forEach(function(p){po+='<option value="'+p+'"'+(j.position===p?' selected':'')+'>'+p+'</option>'});area.style.display='block';area.innerHTML='<div style="background:#0f2744;border:1px solid #1e3a5f;border-radius:10px;padding:16px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px"><h4 style="margin:0;color:#e2e8f0;font-size:14px">'+(esE?'Editar jugador':'Nuevo jugador')+'</h4><button onclick="ppCerrarFormJugador()" style="background:none;border:none;color:#9ca3af;font-size:18px;cursor:pointer">✕</button></div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;margin-bottom:12px"><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Nombre *</label><input type="text" id="ppj-name" value="'+ppEsc(j.name)+'" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Dorsal</label><input type="number" id="ppj-number" value="'+(j.number||'')+'" min="1" max="99" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Posicion</label><select id="ppj-position" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px">'+po+'</select></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Pie</label><select id="ppj-foot" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"><option value="Diestro"'+(j.foot==='Diestro'?' selected':'')+'>Diestro</option><option value="Zurdo"'+(j.foot==='Zurdo'?' selected':'')+'>Zurdo</option><option value="Ambidiestro"'+(j.foot==='Ambidiestro'?' selected':'')+'>Ambidiestro</option></select></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Año</label><input type="number" id="ppj-year" value="'+(j.year||'')+'" min="1970" max="2010" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Procede de</label><input type="text" id="ppj-club" value="'+ppEsc(j.club_from)+'" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div></div><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:12px"><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">PJ</label><input type="number" id="ppj-games" value="'+(j.games||'')+'" min="0" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Min</label><input type="number" id="ppj-minutes" value="'+(j.minutes||'')+'" min="0" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Goles</label><input type="number" id="ppj-goals" value="'+(j.goals||'')+'" min="0" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div></div><div style="margin-bottom:12px"><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Videos del jugador</label><div id="ppj-media-list" style="margin-bottom:6px">'+ppRenderJugadorMedia(j.media||[])+'</div><button type="button" onclick="ppAgregarMediaJugador()" style="padding:5px 12px;background:#0f172a;border:1px solid #334155;color:#94a3b8;border-radius:6px;cursor:pointer;font-size:11px">+ Añadir video/imagen</button></div><div style="margin-bottom:12px"><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Analisis</label><textarea id="ppj-analysis" rows="3" style="width:100%;padding:8px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px;resize:vertical">'+ppEsc(j.analysis)+'</textarea></div><div style="display:flex;gap:8px;justify-content:flex-end">'+(esE?'<button onclick="ppEliminarJugador('+idx+')" style="padding:7px 14px;background:#7f1d1d;border:1px solid #dc2626;color:#fca5a5;border-radius:6px;cursor:pointer;font-size:12px;margin-right:auto">Eliminar</button>':'')+'<button onclick="ppCerrarFormJugador()" style="padding:7px 16px;background:#1e293b;border:1px solid #475569;color:#9ca3af;border-radius:6px;cursor:pointer;font-size:12px">Cancelar</button><button onclick="ppGuardarJugador()" style="padding:7px 16px;background:#3b82f6;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">'+(esE?'Guardar':'Añadir')+'</button></div></div>';area.scrollIntoView({behavior:'smooth',block:'nearest'})}
function ppCerrarFormJugador(){var a=document.getElementById('pp-jugador-form-area');if(a)a.style.display='none';pp.jugadorEditIdx=-1}
async function ppGuardarJugador(){var name=document.getElementById('ppj-name').value.trim();if(!name){showToast('Nombre obligatorio');return}var j={name:name,number:document.getElementById('ppj-number').value?parseInt(document.getElementById('ppj-number').value):null,position:document.getElementById('ppj-position').value||'',foot:document.getElementById('ppj-foot').value||'Diestro',year:document.getElementById('ppj-year').value?parseInt(document.getElementById('ppj-year').value):null,club_from:document.getElementById('ppj-club').value.trim()||'',games:document.getElementById('ppj-games').value?parseInt(document.getElementById('ppj-games').value):null,minutes:document.getElementById('ppj-minutes').value?parseInt(document.getElementById('ppj-minutes').value):null,goals:document.getElementById('ppj-goals').value?parseInt(document.getElementById('ppj-goals').value):null,analysis:document.getElementById('ppj-analysis').value.trim()||'',media:_ppJugadorMedia.slice()};var jug=pp.planActual.rival_players||[];if(pp.jugadorEditIdx>=0)jug[pp.jugadorEditIdx]=j;else jug.push(j);try{var{error}=await supabaseClient.from('match_plans').update({rival_players:jug,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.rival_players=jug;showToast(pp.jugadorEditIdx>=0?'Actualizado':'Añadido');ppCerrarFormJugador();ppMostrarTab('jugadores')}catch(e){showToast('Error: '+e.message)}}
async function ppEliminarJugador(idx){if(!confirm('¿Eliminar?'))return;var jug=pp.planActual.rival_players||[];jug.splice(idx,1);try{var{error}=await supabaseClient.from('match_plans').update({rival_players:jug,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.rival_players=jug;ppCerrarFormJugador();ppMostrarTab('jugadores')}catch(e){showToast('Error: '+e.message)}}

// =============================================
// TAB: FASES TACTICAS
// =============================================
function ppGetFases(){var f=pp.planActual.tactical_phases;if(!f||!Array.isArray(f)||f.length===0)return PP_FASES_DEFAULT.map(function(x){return{id:x.id,title:x.title,notes:'',media:[]}});return f}
function ppRenderFases(){var fases=ppGetFases();var cols=['#0f6e56','#085041','#993c1d','#0c447c','#3c3489','#712b13'];var h='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:20px"><h3 style="margin:0 0 6px;color:#e2e8f0;font-size:16px">⚽ Momentos del juego</h3><p style="margin:0 0 16px;font-size:12px;color:#64748b">Analiza cada fase del rival.</p>';fases.forEach(function(f,i){var mh='';if(f.media&&f.media.length>0){mh='<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:8px">';f.media.forEach(function(m,mi){mh+='<div style="display:flex;align-items:center;gap:6px;background:#0f172a;border:1px solid #334155;border-radius:6px;padding:5px 10px;font-size:11px"><span style="font-size:14px">'+(m.type==='video'?'🎬':(m.type==='image'?'🖼️':'🔗'))+'</span><a href="'+ppEsc(m.url)+'" target="_blank" style="color:#60a5fa;text-decoration:none;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+ppEsc(m.title||'Media')+'</a><button onclick="ppEliminarMediaFase('+i+','+mi+')" style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:14px;padding:0 2px">✕</button></div>'});mh+='</div>'}h+='<div style="background:#1e293b;border-left:4px solid '+cols[i%cols.length]+';border-radius:0 8px 8px 0;padding:14px;margin-bottom:10px"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px"><div style="font-size:13px;font-weight:600;color:#e2e8f0">'+ppEsc(f.title)+'</div><button onclick="ppAgregarMediaFase('+i+')" style="padding:4px 10px;background:#0f172a;border:1px solid #334155;color:#94a3b8;border-radius:6px;cursor:pointer;font-size:11px">+ Video</button></div><textarea id="pp-fase-'+i+'" onchange="ppGuardarFase('+i+',this.value)" rows="3" placeholder="Notas..." style="width:100%;padding:8px 10px;background:#0f172a;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px;resize:vertical">'+ppEsc(f.notes)+'</textarea>'+mh+'</div>'});return h+'</div>'}
async function ppGuardarFase(i,v){var f=ppGetFases();f[i].notes=v||'';try{var{error}=await supabaseClient.from('match_plans').update({tactical_phases:f,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.tactical_phases=f}catch(e){showToast('Error: '+e.message)}}
function ppAgregarMediaFase(idx){var faseCheck=ppGetFases()[idx];if(faseCheck.media&&faseCheck.media.length>=PP_MAX_MEDIA_POR_FASE){showToast('Max '+PP_MAX_MEDIA_POR_FASE+' por fase');return}ppAbrirModalMedia('pp-media-overlay',function(url,title,tipo){ppSaveMediaFase(idx,url,title,tipo)},function(url,title,tipo){ppSaveMediaFase(idx,url,title,tipo)})}
async function ppSaveMediaFase(idx,url,title,tipo){var fases=ppGetFases();if(!fases[idx].media)fases[idx].media=[];fases[idx].media.push({url:url,title:title,type:tipo});try{var{error}=await supabaseClient.from('match_plans').update({tactical_phases:fases,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.tactical_phases=fases;showToast('Añadido');ppMostrarTab('fases')}catch(e){showToast('Error: '+e.message)}}
async function ppEliminarMediaFase(fi,mi){var f=ppGetFases();f[fi].media.splice(mi,1);try{var{error}=await supabaseClient.from('match_plans').update({tactical_phases:f,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.tactical_phases=f;ppMostrarTab('fases')}catch(e){showToast('Error: '+e.message)}}

