function ppCalcularSemana(){var md=new Date(pp.partidoActual.match_date+'T12:00:00');var d=[];for(var i=6;i>=0;i--){var x=new Date(md);x.setDate(x.getDate()-i);d.push({date:x.getFullYear()+'-'+String(x.getMonth()+1).padStart(2,'0')+'-'+String(x.getDate()).padStart(2,'0'),dayName:['Dom','Lun','Mar','Mie','Jue','Vie','Sab'][x.getDay()],md:i===0?'MD':'MD-'+i,dayNum:x.getDate(),month:x.getMonth()+1})}return d}
async function ppCargarSemana(){var d=ppCalcularSemana();pp.semana.dias=d;try{var{data:s}=await supabaseClient.from('training_sessions').select('id,name,session_date,rpe').eq('club_id',clubId).gte('session_date',d[0].date).lte('session_date',d[d.length-1].date).order('session_date');pp.semana.sesiones=s||[];var{data:m}=await supabaseClient.from('training_periods').select('*').eq('club_id',clubId).eq('type','micro').lte('date_start',d[d.length-1].date).gte('date_end',d[0].date).limit(1);pp.semana.microciclo=(m&&m.length>0)?m[0]:null}catch(e){}var a=document.getElementById('pp-tab-content');if(a)a.innerHTML=ppRenderSemana()}
function ppRenderSemana(){var d=pp.semana.dias,s=pp.semana.sesiones,mic=pp.semana.microciclo,p=pp.planActual,wm=p.weekly_map||{},ob=p.weekly_objectives||[];var h='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:20px">';if(mic)h+='<div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;padding:10px 14px;background:#1e293b;border-radius:8px;border-left:4px solid '+(mic.color||'#22c55e')+'"><span style="font-size:13px;font-weight:600;color:#e2e8f0">'+ppEsc(mic.name)+'</span><span style="color:#64748b;font-size:11px">Microciclo</span></div>';h+='<h3 style="margin:0 0 12px;color:#e2e8f0;font-size:16px">📅 Mapa semanal</h3><div style="display:grid;grid-template-columns:repeat(7,1fr);gap:4px;margin-bottom:20px">';d.forEach(function(dia){var eM=dia.md==='MD';var sd=s.filter(function(x){return x.session_date===dia.date});var or=wm[dia.md]||'';h+='<div style="background:'+(eM?'#7f1d1d':'#1e293b')+';border:1px solid '+(eM?'#ef4444':'#334155')+';border-radius:8px;padding:8px;min-height:100px"><div style="text-align:center;margin-bottom:6px"><div style="font-size:10px;color:#64748b;text-transform:uppercase">'+dia.dayName+'</div><div style="font-size:16px;font-weight:700;color:'+(eM?'#fca5a5':'#e2e8f0')+'">'+dia.dayNum+'/'+dia.month+'</div><div style="font-size:11px;font-weight:600;color:'+(eM?'#ef4444':'#f59e0b')+'">'+dia.md+'</div></div>';if(!eM){h+='<select onchange="ppGuardarOrientacion(\''+dia.md+'\',this.value)" style="width:100%;padding:3px 4px;background:#0f172a;border:1px solid #334155;border-radius:4px;color:#94a3b8;font-size:10px;margin-bottom:4px"><option value="">Orientacion...</option>';PP_ORIENTACIONES.forEach(function(o){h+='<option value="'+o+'"'+(or===o?' selected':'')+'>'+o+'</option>'});h+='</select>'}else h+='<div style="text-align:center;font-size:11px;font-weight:600;color:#ef4444;margin-bottom:4px">⚽ PARTIDO</div>';if(sd.length>0)sd.forEach(function(x){h+='<div onclick="cambiarModulo(\'planificador\',document.querySelector(\'.main-tab.planificador\'));setTimeout(function(){cargarSesionEnEditor(\''+x.id+'\')},300)" style="background:#0f172a;border:1px solid #334155;border-radius:4px;padding:4px 6px;margin-top:3px;cursor:pointer;font-size:10px;color:#94a3b8;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">📋 '+ppEsc(x.name.substring(0,15))+(x.rpe?' <span style="color:#f59e0b">RPE:'+x.rpe+'</span>':'')+'</div>'});else if(!eM)h+='<div style="font-size:10px;color:#475569;text-align:center;margin-top:6px">Sin sesion</div>';h+='</div>'});h+='</div><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px"><h3 style="margin:0;color:#e2e8f0;font-size:16px">🎯 Objetivos ('+ob.length+')</h3><button onclick="ppAbrirFormObjetivo(-1)" style="padding:6px 14px;background:#3b82f6;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">+ Añadir</button></div><div id="pp-obj-form-area" style="display:none;margin-bottom:12px"></div>';if(ob.length===0)h+='<div style="padding:20px;background:#1e293b;border-radius:8px;text-align:center;color:#475569;font-size:13px">Sin objetivos</div>';else{h+='<div style="display:flex;flex-direction:column;gap:6px">';ob.forEach(function(o,i){var ti=PP_TIPOS_OBJ.find(function(t){return t.id===o.type})||PP_TIPOS_OBJ[5];h+='<div style="display:flex;align-items:center;gap:10px;background:#1e293b;border:1px solid #334155;border-radius:8px;padding:10px 14px;cursor:pointer" onclick="ppAbrirFormObjetivo('+i+')" onmouseenter="this.style.borderColor=\'#3b82f6\'" onmouseleave="this.style.borderColor=\'#334155\'"><div style="width:8px;height:8px;border-radius:50%;background:'+ti.color+'"></div><div style="flex:1;min-width:0"><div style="font-size:13px;color:#e2e8f0">'+ppEsc(o.text)+'</div>'+(o.activities?'<div style="font-size:11px;color:#64748b;margin-top:2px">'+ppEsc(o.activities)+'</div>':'')+'</div><span style="padding:2px 8px;background:#0f172a;border:1px solid #334155;border-radius:4px;font-size:10px;color:'+ti.color+';font-weight:600">'+ti.label+'</span>'+(o.session_day?'<span style="padding:2px 8px;background:#0f172a;border:1px solid #334155;border-radius:4px;font-size:10px;color:#f59e0b;font-weight:600">'+o.session_day+'</span>':'')+'</div>'});h+='</div>'}return h+'</div>'}
async function ppGuardarOrientacion(md,v){var wm=pp.planActual.weekly_map||{};wm[md]=v||'';try{var{error}=await supabaseClient.from('match_plans').update({weekly_map:wm,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.weekly_map=wm}catch(e){showToast('Error: '+e.message)}}
function ppAbrirFormObjetivo(idx){pp.objEditIdx=idx;var a=document.getElementById('pp-obj-form-area');if(!a)return;var ob=pp.planActual.weekly_objectives||[];var o=idx>=0?ob[idx]:{text:'',type:'ofensivo',session_day:'',activities:''};var esE=idx>=0;var to='';PP_TIPOS_OBJ.forEach(function(t){to+='<option value="'+t.id+'"'+(o.type===t.id?' selected':'')+'>'+t.label+'</option>'});var dO='<option value="">Sin asignar</option>';pp.semana.dias.forEach(function(d){if(d.md!=='MD')dO+='<option value="'+d.md+'"'+(o.session_day===d.md?' selected':'')+'>'+d.md+' ('+d.dayName+' '+d.dayNum+'/'+d.month+')</option>'});a.style.display='block';a.innerHTML='<div style="background:#0f2744;border:1px solid #1e3a5f;border-radius:10px;padding:14px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><h4 style="margin:0;color:#e2e8f0;font-size:14px">'+(esE?'Editar':'Nuevo objetivo')+'</h4><button onclick="ppCerrarFormObjetivo()" style="background:none;border:none;color:#9ca3af;font-size:18px;cursor:pointer">✕</button></div><div style="margin-bottom:10px"><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Objetivo *</label><input type="text" id="ppo-text" value="'+ppEsc(o.text)+'" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px"><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Tipo</label><select id="ppo-type" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px">'+to+'</select></div><div><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Sesion</label><select id="ppo-day" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px">'+dO+'</select></div></div><div style="margin-bottom:10px"><label style="font-size:11px;color:#9ca3af;display:block;margin-bottom:3px">Actividades</label><input type="text" id="ppo-activities" value="'+ppEsc(o.activities)+'" style="width:100%;padding:7px 10px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div style="display:flex;gap:8px;justify-content:flex-end">'+(esE?'<button onclick="ppEliminarObjetivo('+idx+')" style="padding:7px 14px;background:#7f1d1d;border:1px solid #dc2626;color:#fca5a5;border-radius:6px;cursor:pointer;font-size:12px;margin-right:auto">Eliminar</button>':'')+'<button onclick="ppCerrarFormObjetivo()" style="padding:7px 16px;background:#1e293b;border:1px solid #475569;color:#9ca3af;border-radius:6px;cursor:pointer;font-size:12px">Cancelar</button><button onclick="ppGuardarObjetivo()" style="padding:7px 16px;background:#3b82f6;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">'+(esE?'Guardar':'Añadir')+'</button></div></div>';a.scrollIntoView({behavior:'smooth',block:'nearest'})}
function ppCerrarFormObjetivo(){var a=document.getElementById('pp-obj-form-area');if(a)a.style.display='none';pp.objEditIdx=-1}
async function ppGuardarObjetivo(){var t=document.getElementById('ppo-text').value.trim();if(!t){showToast('Obligatorio');return}var o={text:t,type:document.getElementById('ppo-type').value,session_day:document.getElementById('ppo-day').value||'',activities:document.getElementById('ppo-activities').value.trim()||''};var ob=pp.planActual.weekly_objectives||[];if(pp.objEditIdx>=0)ob[pp.objEditIdx]=o;else ob.push(o);try{var{error}=await supabaseClient.from('match_plans').update({weekly_objectives:ob,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.weekly_objectives=ob;ppCerrarFormObjetivo();ppCargarSemana()}catch(e){showToast('Error: '+e.message)}}
async function ppEliminarObjetivo(i){if(!confirm('¿Eliminar?'))return;var ob=pp.planActual.weekly_objectives||[];ob.splice(i,1);try{var{error}=await supabaseClient.from('match_plans').update({weekly_objectives:ob,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.weekly_objectives=ob;ppCerrarFormObjetivo();ppCargarSemana()}catch(e){showToast('Error: '+e.message)}}

