function ppRenderContenidos(){var p=pp.planActual;var ejs=p.linked_exercises||[];var abps=p.linked_abps||[];var vids=p.tacticlip_videos||[];var h='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;padding:20px"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px"><h3 style="margin:0;color:#e2e8f0;font-size:16px">🎯 Ejercicios ('+ejs.length+')</h3><button onclick="ppBuscarEjercicio(\'exercise\')" style="padding:6px 14px;background:#3b82f6;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">+ Vincular</button></div>';if(ejs.length===0)h+='<div style="padding:16px;background:#1e293b;border-radius:8px;text-align:center;color:#475569;font-size:12px;margin-bottom:20px">Vincula ejercicios de la pizarra</div>';else{h+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:8px;margin-bottom:20px">';ejs.forEach(function(e,i){h+=ppRenderEjCard(e,i,'exercise')});h+='</div>'}h+='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px"><h3 style="margin:0;color:#a855f7;font-size:16px">⚽ ABPs ('+abps.length+')</h3><button onclick="ppBuscarEjercicio(\'abp\')" style="padding:6px 14px;background:#a855f7;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">+ Vincular ABP</button></div>';if(abps.length===0)h+='<div style="padding:16px;background:#1e293b;border-radius:8px;text-align:center;color:#475569;font-size:12px;margin-bottom:20px">Selecciona ABPs</div>';else{h+='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:8px;margin-bottom:20px">';abps.forEach(function(e,i){h+=ppRenderEjCard(e,i,'abp')});h+='</div>'}h+='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px"><h3 style="margin:0;color:#f97316;font-size:16px">🎬 Videos ('+vids.length+')</h3><button onclick="ppAgregarTactiClip()" style="padding:6px 14px;background:#f97316;border:none;color:#fff;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">+ Añadir</button></div>';if(vids.length===0)h+='<div style="padding:16px;background:#1e293b;border-radius:8px;text-align:center;color:#475569;font-size:12px">Videos tacticos <div style="margin-top:8px"><a href="https://tacticlipfutbol.com/" target="_blank" style="color:#f97316;font-size:11px;text-decoration:none">TactiClip: TOPLIDER20</a></div></div>';else{h+='<div style="display:flex;flex-direction:column;gap:6px">';vids.forEach(function(v,i){var tc=v.url&&v.url.indexOf('tacticlip')>=0;h+='<div style="display:flex;align-items:center;gap:10px;background:#1e293b;border:1px solid #334155;border-radius:8px;padding:10px 14px"><span style="font-size:14px">'+(tc?'🏷️':'🎬')+'</span><div style="flex:1;min-width:0"><a href="'+ppEsc(v.url)+'" target="_blank" style="color:#60a5fa;text-decoration:none;font-size:13px">'+ppEsc(v.title||v.url)+'</a>'+(v.description?'<div style="font-size:11px;color:#64748b;margin-top:2px">'+ppEsc(v.description)+'</div>':'')+'</div>'+(tc?'<span style="font-size:9px;color:#f97316;background:#431407;padding:2px 6px;border-radius:4px">TactiClip</span>':'')+'<button onclick="ppEliminarTactiClip('+i+')" style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:16px">✕</button></div>'});h+='</div>'}return h+'</div>'}
function ppRenderEjCard(ej,idx,tipo){var hs=ej.thumbnail_svg&&ej.thumbnail_svg.length>100;return '<div style="background:#0f172a;border:1px solid '+(tipo==='abp'?'#7c3aed':'#334155')+';border-radius:10px;padding:10px;position:relative"><button onclick="event.stopPropagation();ppDesvincularEjercicio('+idx+',\''+tipo+'\')" style="position:absolute;top:6px;right:6px;background:#7f1d1d;border:none;color:#fca5a5;cursor:pointer;font-size:12px;width:20px;height:20px;border-radius:50%;display:flex;align-items:center;justify-content:center;z-index:1">✕</button>'+(hs?'<div style="width:100%;aspect-ratio:8/5;border-radius:6px;overflow:hidden;background:#0f4c2a;margin-bottom:6px">'+ej.thumbnail_svg+'</div>':'<div style="width:100%;aspect-ratio:8/5;border-radius:6px;background:#1e293b;display:flex;align-items:center;justify-content:center;margin-bottom:6px;font-size:24px;color:#334155">🎨</div>')+'<div style="font-size:12px;font-weight:600;color:#e2e8f0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+ppEsc(ej.name)+(ej.animation_url?' <span style="color:#f97316;font-size:10px">🎬</span>':'')+'</div>'+(ej.category?'<div style="font-size:10px;color:#64748b">'+ppEsc(ej.category)+(ej.tema?' · '+ppEsc(ej.tema):'')+'</div>':'')+'</div>'}
async function ppBuscarEjercicio(tipo){var prev=document.getElementById('pp-ej-overlay');if(prev)prev.remove();var ov=document.createElement('div');ov.id='pp-ej-overlay';ov.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.75);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';ov.onclick=function(e){if(e.target===ov)ov.remove()};ov.innerHTML='<div style="background:#0f172a;border:1px solid #1e3a5f;border-radius:12px;max-width:700px;width:100%;max-height:80vh;display:flex;flex-direction:column"><div style="padding:16px 20px;border-bottom:1px solid #1e3a5f;display:flex;justify-content:space-between;align-items:center"><h3 style="margin:0;color:#e2e8f0;font-size:16px">'+(tipo==='abp'?'Vincular ABP':'Vincular ejercicio')+'</h3><button onclick="document.getElementById(\'pp-ej-overlay\').remove()" style="background:none;border:none;color:#9ca3af;font-size:20px;cursor:pointer">✕</button></div><div style="padding:12px 20px;border-bottom:1px solid #1e3a5f"><input type="text" id="pp-ej-search" oninput="ppFiltrarEjercicios(\''+tipo+'\')" placeholder="Buscar..." style="width:100%;padding:8px 12px;background:#1e293b;border:1px solid #334155;border-radius:6px;color:#e2e8f0;font-size:13px"></div><div id="pp-ej-results" style="flex:1;overflow-y:auto;padding:12px 20px"><div style="text-align:center;padding:20px;color:#64748b">Cargando...</div></div></div>';document.body.appendChild(ov);try{var{data,error}=await supabaseClient.from('custom_exercises').select('id,name,category,tema,objectives,thumbnail_svg,animation_url').eq('coach_id',String(typeof usuario!=='undefined'?usuario.id:'')).order('name');if(error)throw error;window._ppEjCache=data||[];ppFiltrarEjercicios(tipo)}catch(e){document.getElementById('pp-ej-results').innerHTML='<div style="color:#ef4444;text-align:center;padding:20px">Error: '+e.message+'</div>'}}
function ppFiltrarEjercicios(tipo){var s=(document.getElementById('pp-ej-search')?.value||'').toLowerCase();var r=document.getElementById('pp-ej-results');if(!r)return;var ya=tipo==='abp'?(pp.planActual.linked_abps||[]):(pp.planActual.linked_exercises||[]);var ids=ya.map(function(e){return e.id});var f=(window._ppEjCache||[]).filter(function(e){return ids.indexOf(e.id)<0&&(!s||((e.name||'')+' '+(e.category||'')+' '+(e.tema||'')).toLowerCase().indexOf(s)>=0)});if(f.length===0){r.innerHTML='<div style="text-align:center;padding:20px;color:#64748b">Sin resultados</div>';return}var h='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:8px">';f.forEach(function(e){h+='<div onclick="ppVincularEjercicio(\''+e.id+'\',\''+tipo+'\')" style="background:#1e293b;border:1px solid #334155;border-radius:8px;padding:8px;cursor:pointer" onmouseenter="this.style.borderColor=\''+(tipo==='abp'?'#a855f7':'#3b82f6')+'\'" onmouseleave="this.style.borderColor=\'#334155\'">'+(e.thumbnail_svg&&e.thumbnail_svg.length>100?'<div style="width:100%;aspect-ratio:8/5;border-radius:6px;overflow:hidden;background:#0f4c2a">'+e.thumbnail_svg+'</div>':'<div style="width:100%;aspect-ratio:8/5;border-radius:6px;background:#1e293b;display:flex;align-items:center;justify-content:center;font-size:20px;color:#334155">🎨</div>')+'<div style="font-size:11px;font-weight:600;color:#e2e8f0;margin-top:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+ppEsc(e.name)+'</div><div style="font-size:10px;color:#64748b">'+ppEsc(e.category||'')+'</div></div>'});r.innerHTML=h+'</div>'}
async function ppVincularEjercicio(ejId,tipo){var ej=(window._ppEjCache||[]).find(function(e){return e.id===ejId});if(!ej)return;var campo=tipo==='abp'?'linked_abps':'linked_exercises';var lista=pp.planActual[campo]||[];lista.push({id:ej.id,name:ej.name,category:ej.category||'',tema:ej.tema||'',objectives:ej.objectives||'',thumbnail_svg:ej.thumbnail_svg||'',animation_url:ej.animation_url||''});try{var up={updated_at:new Date().toISOString()};up[campo]=lista;var{error}=await supabaseClient.from('match_plans').update(up).eq('id',pp.planActual.id);if(error)throw error;pp.planActual[campo]=lista;showToast('Vinculado');var ov=document.getElementById('pp-ej-overlay');if(ov)ov.remove();ppMostrarTab('contenido')}catch(e){showToast('Error: '+e.message)}}
async function ppDesvincularEjercicio(idx,tipo){if(!confirm('¿Desvincular?'))return;var campo=tipo==='abp'?'linked_abps':'linked_exercises';var lista=pp.planActual[campo]||[];lista.splice(idx,1);try{var up={updated_at:new Date().toISOString()};up[campo]=lista;var{error}=await supabaseClient.from('match_plans').update(up).eq('id',pp.planActual.id);if(error)throw error;pp.planActual[campo]=lista;ppMostrarTab('contenido')}catch(e){showToast('Error: '+e.message)}}
function ppAgregarTactiClip(){ppAbrirModalMedia('pp-tc-overlay',function(url,title,tipo){ppSaveTactiClip(url,title,'')},function(url,title,tipo){ppSaveTactiClip(url,title,'')})}
async function ppSaveTactiClip(url,title,desc){var vids=pp.planActual.tacticlip_videos||[];vids.push({url:url,title:title,description:desc});try{var{error}=await supabaseClient.from('match_plans').update({tacticlip_videos:vids,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.tacticlip_videos=vids;showToast('Añadido');ppMostrarTab('contenido')}catch(e){showToast('Error: '+e.message)}}
async function ppEliminarTactiClip(i){if(!confirm('¿Eliminar?'))return;var v=pp.planActual.tacticlip_videos||[];v.splice(i,1);try{var{error}=await supabaseClient.from('match_plans').update({tacticlip_videos:v,updated_at:new Date().toISOString()}).eq('id',pp.planActual.id);if(error)throw error;pp.planActual.tacticlip_videos=v;ppMostrarTab('contenido')}catch(e){showToast('Error: '+e.message)}}

